// Axios version (alternative if you prefer axios)
export const uploadImageWithAxios = async (formData) => {
  try {
    // Dynamic import of axios (only if needed)
    const axios = (await import('axios')).default;
    
    const response = await axios.post(`${API_BASE_URL}/disease/predict`, formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
        ...(localStorage.getItem('authToken') && {
          'Authorization': `Bearer ${localStorage.getItem('authToken')}`
        })
      },
      onUploadProgress: (progressEvent) => {
        const percentCompleted = Math.round((progressEvent.loaded * 100) / progressEvent.total);
        console.log(`Upload progress: ${percentCompleted}%`);
      }
    });
    
    return response.data;
  } catch (error) {
    console.error('Axios upload error:', error);
    if (error.response) {
      // The request was made and the server responded with a status code
      throw new Error(error.response.data.error || error.response.data.message || 'Upload failed');
    } else if (error.request) {
      // The request was made but no response was received
      throw new Error('No response from server. Please check if backend is running.');
    } else {
      // Something happened in setting up the request
      throw new Error(error.message || 'Upload failed');
    }
  }
};

